var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"음…… 여긴 아무것도 없네. 얘들아, 혹시 찾은 거 있어?","JPN":"うーん……ここには何もないね。みんな、そっちは何かあった？","ENG":"Mm... There is nothing here. Girls, did you find anything?","TWN":"嗯……這裡什麼都沒有。大家有找到什麼嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"꽝이야. 내 탐지 드론도 반응이 없어.","JPN":"ダメだよ。ぼくの探知ドローンも反応なし。","ENG":"Nope. My detection drone's got nothing.","TWN":"沒有。我的探測無人機也沒有反應。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"조금만 더 열심히 찾아보자.","JPN":"もう少し頑張って探してみよう。","ENG":"Let's try looking a little harder.","TWN":"再找找看吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"퀘스트를 깨면, 선배도 분명 최고의 히어로를 찾는 걸 계속 도와줄 거야.","JPN":"クエストをクリアすれば、きっと先輩も最高のヒーロー探しを手伝ってくれるよ。","ENG":"If we complete the quest, Naielle will surely help us find the best hero.","TWN":"完成任務後，前輩也一定會幫助我們尋找最強英雄的。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"잘 들어. 분명 상품은 몬스터가 지키고 있다고 했지, 드랍된다고는 안 했어.","JPN":"いい？　確か賞品はモンスターが守っているって言ってたよね。ドロップするとは言ってない。","ENG":"Listen. It says a monster is protecting the prize, but nothing about it dropping the prize.","TWN":"聽好了，獎品是由怪物守護的，可沒說會掉落。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L11_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"저 총 든 땅꼬마가 플레이어들을 매수한 것 같은데, 내가 이목을 끌고 있을게.","JPN":"あの銃を持ってるチビがプレイヤーを買収してるっぽいけど、私が注意を引くわ。","ENG":"That little girl with a gun seems to have bribed players into helping her, but I'll distract her.","TWN":"那個拿槍的矮冬瓜好像收買了玩家，我來分散注意力。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"그동안 너희들은 이 주변을 샅샅이 뒤져서 상품을 찾아내는 거야. 알겠어?","JPN":"その間、あんたたちはこの辺をくまなく調べて賞品を見つけるのよ。わかった？","ENG":"In the meantime, you all should go look for the prize, got that?","TWN":"這段時間你們要徹底搜查這附近，找到獎品，明白了嗎？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"하하, 그 단순 무식한 선배가 이런 작전도 짤 수 있게 됐다니, 놀라운걸?","JPN":"はは、あの単細胞な先輩がこんな作戦を立てるようになるなんて、びっくりだね。","ENG":"Haha. I'm surprised the simple-minded Naielle is now able to plan something like this.","TWN":"哈哈，那個單純又魯莽的前輩竟然也能制定這樣的作戰計畫，真是令人驚訝啊？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L15_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"얘들아 이것 좀 봐! 여기 보물 상자가 있어!","JPN":"みんな、これ見て！　ここに宝箱があるよ！","ENG":"Girls, look! There's a treasure chest here!","TWN":"大家快看！這裡有個寶箱！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"헤헤, 분명 이 안에 굿즈가 들어있을……","JPN":"えへへ、きっとこの中にグッズが……","ENG":"Hehe, I'm sure the merchandise is inside–","TWN":"嘿嘿，裡面一定有周邊……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L20_1","type":"dialog","speaker":"STAR_LEGACY_NULL_QM","text":{"KOREA":"하하, 쉬워 보이는 길은 죄다 지뢰밭이라는 거, 보라가 안 가르치든?\xA0","JPN":"はは、なにもなさそうなところに罠があるって、シホが教えてくれへんかった？\xA0","ENG":"Haha! Didn't Bora teach ya that any path that looks easy is a minefield?\xA0","TWN":"哈哈，看起來容易的路全都是地雷區，寶拉沒教過你嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"네, 네……?","JPN":"え、えっ……？","ENG":"W-what...?","TWN":"啊？啥……？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"하하, 겨우 여기까지야? 난 하루 종일이라도 싸울 수 있다고!","JPN":"あはは、もう終わり？　私は一日中だって戦えるわ！","ENG":"Haha, is that it? I can do this all day!","TWN":"哈哈，就這點本事嗎？我可是能打上一整天的！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MIYA_HB_VAL_NULL","text":{"KOREA":"대, 대단해요 아카데미 학생들이 혈맹단을 상대로 전혀 밀리지 않고 있어요!","JPN":"す、すごい！　アカデミーの生徒たち、血盟団相手に引けを取ってません！","ENG":"I-incredible. The Academy students are going head-to-head with the Blood Alliance!","TWN":"太，太厲害了，學院學生們完全沒有被血盟團壓制住！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"MIYA_HB_VAL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>■■■</color> 콜라보 퀘스트는 아예 뒷전이 되어버린 거야?\\n<color=#ffd34c>■■■</color> 브로마이드 사진 보여줘! 채널에 들어가니까 모자이크 되어있더만!!","JPN":"<color=#ffd34c>■■■</color> コラボクエストは？\\n<color=#ffd34c>■■■</color> ブロマイド写真見せてよ！　チャンネル見たらモザイクかけてあるじゃんか！！","ENG":"<color=#ffd34c>■■■</color> Has the collaboration quest been put on the back burner?\\n<color=#ffd34c>■■■</color> Show me the poster photo! It's blurred out in the channel!!","TWN":"<color=#ffd34c>■■■</color>根本沒人在管聯動任務吧？\\n<color=#ffd34c>■■■</color>我要看海報上的照片！頻道裡的有打馬賽克！！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MIYA_HB_VAL_NULL","text":{"KOREA":"으아아~ 비난 채팅이 엄청 올라오고 있잖아!","JPN":"うわあ～不満の書き込みがすごいです！！","ENG":"Ooh...! Chat's getting riled up!","TWN":"哎呀，網上的批評和抱怨好像越來越多了呢！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_VAL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MIYA_HB_VAL_NULL","text":{"KOREA":"마, 마이크 비워서 죄송해요! 나중에 벌칙 미션 받을게요!","JPN":"す、すみません！　あとで罰ゲームしますから！","ENG":"S-sorry for not talking! I'll do a penalty mission later!","TWN":"哎呀，不好意思，麥克風沒聲音了！我會接受懲罰任務的！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_VAL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"XIEN_FREEDOM_NULL_NULL","text":{"KOREA":"훗훗, 최고의 전투로군. 왕년에 겪었던 해변의 전투가 떠오를 정도야!","JPN":"ふふっ、最高の戦いだね。昔海辺で経験した熱い戦闘を思い出すよ！","ENG":"Hah hah, what a great battle. It reminds me of a battle by the beach I had a long time ago!","TWN":"哼哼，真是一場精彩的戰鬥。讓我想起了當年在海灘上的戰鬥！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"잠깐, 그나저나 뭔가 이상하지 않아요?","JPN":"ちょっと、何かおかしくないですか？","ENG":"Wait. Something seems off.","TWN":"等一下，話說回來，不覺得有些奇怪嗎？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L35_1","type":"dialog","speaker":"XIEN_FREEDOM_NULL_NULL","text":{"KOREA":"응? 갑자기 왜?","JPN":"ん？　急にどうした？","ENG":"Hmm? What's wrong?","TWN":"嗯？突然怎麼了？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"이쯤 되면 브로마이드가 나와줘야 하는데 왜 발견한 사람이 아무도 없죠?","JPN":"さすがにそろそろブロマイドが出てきてもいいのに……なんでまだ誰も見つけられてないんでしょう？","ENG":"Someone should have found the poster by now, but it hasn't been found yet.","TWN":"這個時候應該要有海報出現了，為什麼沒有人發現呢？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"XIEN_FREEDOM_NULL_NULL","text":{"KOREA":"아 그랬지! 전장의 열기가 너무 뜨겁다 보니 잊고 있었어!","JPN":"あっ、そうだった！　戦場の熱気があまりにも熱くてすっかり忘れてた！","ENG":"Oh, right! I got swept up in the heat of battle and forgot!","TWN":"啊，對欸！打得太激烈，我都忘了！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L40_1","type":"dialog","speaker":"BLOOD_LEGACY_NULL_EXTRAA","text":{"KOREA":"제길, 대체 왜 뜨질 않는 거냐고!","JPN":"くそ、なんで出てこないんだよ！","ENG":"Dammit! Where is it?!","TWN":"該死，到底為什麼不顯示！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BLOOD_LEGACY_NULL_EXTRAA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BLOOD_LEGACY_NULL_EXTRAB","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"BLOOD_LEGACY_NULL_EXTRAB","text":{"KOREA":"설마 당신들이 빼돌린 거 아닙니까?","JPN":"あなたたちが横取りしたのでは？","ENG":"You didn't take it for yourselves, did you?","TWN":"不會是你們偷走的吧？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BLOOD_LEGACY_NULL_EXTRAA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BLOOD_LEGACY_NULL_EXTRAB","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"BLOOD_LEGACY_NULL_EXTRAB","text":{"KOREA":"전 미야 씨의 브로마이드를 위해 시골에서 힘들게 상경한 거라고요!","JPN":"僕はミヤさんのブロマイドのために、田舎から来たんですよ！　ここ来るの大変だったんですから！","ENG":"I came here from the countryside just to see Miya's poster!","TWN":"我是為了米婭的海報才從鄉下辛苦來到這裡的！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BLOOD_LEGACY_NULL_EXTRAA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BLOOD_LEGACY_NULL_EXTRAB","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"그딴 거 알 게 뭐야! 지금 우릴 의심하는 거예요?!","JPN":"そんなこと知りません！　まさか秋たちを疑ってるんですか？","ENG":"So what?! Are you accusing us of stealing it?!","TWN":"那種事我怎麼知道！你現在是在懷疑我們嗎？！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L46_1","type":"dialog","speaker":"XIEN_FREEDOM_NULL_NULL","text":{"KOREA":"분열은 안 돼! 이러면 혈맹단의 명성이 우스워진다고!","JPN":"仲間割れはダメだ！　こんなんじゃ血盟団の名声に傷がつく！","ENG":"No internal conflicts! It will only bring down the reputation of the Blood Alliance!","TWN":"不要內訌！這樣只會讓血盟團遭人笑話！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L47_1","type":"dialog","speaker":"STAR_LEGACY_NULL_QM","text":{"KOREA":"니들 거기까지 안 하나!!","JPN":"そこまでや！！","ENG":"That's as far as y'all go!!","TWN":"到此為止吧！！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MIYA_HB_VAL_NULL","text":{"KOREA":"무, 무슨 일이 일어난 거죠? 연기 때문에 아무것도 안 보여요……!","JPN":"な、何が起こったのでしょう？　煙のせいで何も見えません……！","ENG":"W-what's going on? I can't see anything with all the smoke...!","TWN":"發，發生了什麼事？煙霧繚繞，什麼都看不見……！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_VAL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"뭐, 뭐야……? 무슨 일이 일어난 건데?","JPN":"な、何……？　何が起きたの？","ENG":"H-huh...? What's happening?","TWN":"什，什麼啊……？發生什麼事了？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"STAR_LEGACY_NULL_QM","text":{"KOREA":"퀘스트는 여까지다.","JPN":"クエストはここまでや。","ENG":"The quest is over.","TWN":"任務到此為止。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"STAR_LEGACY_NULL_QM","text":{"KOREA":"니들이 신나게 노는 동안, 보물은 내가 접수했다!","JPN":"あんたらが楽しく遊んでる間に、宝はウチがいただいたで！","ENG":"While y'all were dillydallying, I took the treasure!","TWN":"你們玩得正開心的時候，寶物我就已經收下了！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_LEGACY_NULL_QM","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L5_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"……뭐, 뭐야 저 사람은?!","JPN":"……な、何よあの人！？","ENG":"...W-who are you?!","TWN":"……什，什麼，那個人是？！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};